import React from 'react';

function Projects({ data }) {
  if (!data || data.length === 0) return null;

  return (
    <section id="projects" className="py-12 md:py-16 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-12">
          Projects
        </p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {data.map((project, index) => (
            <div 
              key={project.id} 
              className="group cursor-pointer border-b border-gray-200 pb-8"
            >
              {/* Project Image Container */}
              <div className="relative overflow-hidden bg-gray-100 h-48 mb-6">
                <div className="w-full h-full bg-gray-200 flex items-center justify-center overflow-hidden">
                  {project.image ? (
                    <img 
                      src={project.image} 
                      alt={project.title}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                    />
                  ) : (
                    <div className="w-full h-full bg-gray-300 flex items-center justify-center">
                      <span className="text-5xl text-gray-600">{project.icon}</span>
                    </div>
                  )}
                </div>
              </div>
              
              {/* Project Info */}
              <h3 className="text-lg font-black text-gray-900 mb-2 group-hover:text-gray-600 transition-colors duration-200 line-clamp-2">
                {project.title}
              </h3>
              <p className="text-gray-600 text-sm font-medium line-clamp-1">
                {project.company}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Projects;
